import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { validateRequestUser } from '@/lib/auth-server';
import { broadcastUpdate } from '@/lib/events';

export const dynamic = 'force-dynamic';

// POST /api/items/[id]/use - Mark item as "Used Up"
export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    // 1. Authenticate user
    const user = await validateRequestUser(req);
    if (!user) {
      return NextResponse.json(
        { error: 'Unauthorized. Please log in first.' },
        { status: 401 }
      );
    }

    // 2. Check if item exists
    const existingItem = await prisma.item.findUnique({
      where: { id },
    });

    if (!existingItem) {
      return NextResponse.json(
        { error: 'Item not found.' },
        { status: 404 }
      );
    }

    if (existingItem.status === 'used') {
      return NextResponse.json(
        { error: 'Item is already marked as used up.' },
        { status: 400 }
      );
    }

    // 3. Mark as used and record who did it and last touched it
    const updatedItem = await prisma.item.update({
      where: { id },
      data: {
        status: 'used',
        usedUpById: user.id,
        lastTouchedById: user.id,
      },
      include: {
        addedBy: { select: { id: true, name: true } },
        lastTouchedBy: { select: { id: true, name: true } },
        usedUpBy: { select: { id: true, name: true } },
      },
    });

    // 4. Broadcast event
    broadcastUpdate('use', updatedItem);

    return NextResponse.json(updatedItem);
  } catch (error) {
    console.error('POST /api/items/[id]/use error:', error);
    return NextResponse.json(
      { error: 'Failed to mark item as used.' },
      { status: 500 }
    );
  }
}
